#!/usr/bin/env python3
import os, base64

files = [
  ('app\\\\tracker\\\\page.tsx', ''),
  ('app\\\\api\\\\tracker\\\\route.ts', ''),
]

for win_path, b64 in files:
    path = win_path.replace("\\\\", os.sep).replace("\\", os.sep)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(b64))
    print(f"Written: {path}")
print("\nDone — git add . && git commit -m \"Tracker expandable daily rows\" && vercel --prod")
